sys_script_include.script:
const NavigatorHistory = Class.create();
NavigatorHistory.prototype = {
    initialize: function (options) {
        this.transactionId = options.transactionId || gs.generateGUID();
        this.logger = new Logger({
            transactionId: this.transactionId,
            source: this.type,
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });
    },

    getHistoryEntries: function () {
        const historyEntries = [];
        const historyEntry = new GlideRecord(
            Constants.NAVIGATION_HISTORY_TABLE,
        );
        historyEntry.addQuery("user", gs.getUserID());
        historyEntry.orderByDesc("last_accessed");
        historyEntry.setLimit(10);
        historyEntry.query();

        while (historyEntry.next()) {
            historyEntries.push({
                url: historyEntry.getValue("url"),
                title: historyEntry.getValue("title"),
                subtitle: historyEntry.getValue("subtitle"),
                lastAccessed: historyEntry.getValue("last_accessed"),
            });
        }

        return historyEntries;
    },

    upsertHistoryEntry: function (url) {
        if (!url) {
            this.logger.error("upsertHistoryEntry called with no url");
            return;
        }

        const relativeUrl = this._getRelativeUrlWithParams(url);

        const existingEntry = this._getNavigatorHistoryEntry(relativeUrl);
        if (existingEntry) {
            this._updateNavigatorHistoryEntry(existingEntry.getUniqueValue());
            return;
        }

        const subtitle = this._getSubtitleFromUrl(url);
        const title = this._getTitleFromUrl(url);
        const transformedTitle = this._transformTitle(title);

        this._insertNavigatorHistoryEntry(
            relativeUrl,
            transformedTitle,
            subtitle,
        );
    },

    _getNavigatorHistoryEntry: function (relativeUrl) {
        const historyEntry = new GlideRecord(
            Constants.NAVIGATION_HISTORY_TABLE,
        );
        historyEntry.addQuery("url", relativeUrl);
        historyEntry.addQuery("user", gs.getUserID());
        historyEntry.setLimit(1);
        historyEntry.query();

        if (historyEntry.next()) {
            return historyEntry;
        }
    },

    _insertNavigatorHistoryEntry: function (relativeUrl, title, subtitle) {
        const historyEntry = new GlideRecord(
            Constants.NAVIGATION_HISTORY_TABLE,
        );
        historyEntry.initialize();
        historyEntry.setValue("url", relativeUrl);
        historyEntry.setValue("title", title);
        historyEntry.setValue("subtitle", subtitle);
        historyEntry.setValue("user", gs.getUserID());
        historyEntry.setValue("last_accessed", new GlideDateTime());
        historyEntry.insert();
    },

    _updateNavigatorHistoryEntry: function (entrySysId) {
        const historyEntry = new GlideRecord(
            Constants.NAVIGATION_HISTORY_TABLE,
        );
        if (historyEntry.get(entrySysId)) {
            historyEntry.setValue("last_accessed", new GlideDateTime());
            historyEntry.update();
        }
    },

    _getRelativeUrlWithParams: function (url) {
        const normalizedUrl = String(url).trim();
        const withoutDomain = normalizedUrl.replace(
            /^[a-zA-Z]+:\/\/[^/]+\/?/,
            "",
        );

        return withoutDomain.replace(/^\/+/, "");
    },

    _getSubtitleFromUrl: function (url) {
        const subtitleRegex = /[?&]scm_record_id=([^&#]*)/;
        const subtitleMatch = url.match(subtitleRegex);
        return subtitleMatch ? subtitleMatch[1] : null;
    },

    _getTitleFromUrl: function (url) {
        const titleRegex = /[?&]id=([^&#]*)/;
        const titleMatch = url.match(titleRegex);
        return titleMatch ? titleMatch[1] : null;
    },

    _transformTitle: function (title) {
        if (!title) return null;
        return title
            .split("_")
            .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
            .join(" ");
    },

    type: "NavigatorHistory",
};
